#include <bits/stdc++.h>
using namespace std;
int t,n,a[50004];
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        map<int,int> sum;
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i]);
            if(!sum[a[i]]++)
                printf("%d ",a[i]);
        }
        printf("\n");
    }
    return 0;
}
